function getDepartureCoords(departure: string): { lat: number; lng: number } | null {
  if (!departure) return null;
  const key = departure.toLowerCase().trim();
  if (CITY_COORDS[key]) return CITY_COORDS[key];
  // Partial match — handles "Surat, Gujarat" or "Surat city" etc.
  for (const city of Object.keys(CITY_COORDS)) {
    if (key.includes(city)) return CITY_COORDS[city];
  }
  return null;
}

export function matchDestinations(
  purpose: TripPurpose,
  budget: BudgetTier,
  days: number,
  departure: string,
  _relaxed = false          // internal flag used by the fallback retry
): DestinationCard[] {
  const budgetMax: Record<BudgetTier, number> = { budget: 1200, mid: 3000, premium: 99999 };
  const maxCost = budgetMax[budget];

  const depCoords = getDepartureCoords(departure);

  // Max straight-line distance (km) a traveller can reasonably cover given trip length:
  //   1-2 days  → 500 km  (same-day road/train travel)
  //   3-4 days  → 1000 km (one short flight, or overnight train)
  //   5+ days   → anywhere in India
  const maxDistanceKm = _relaxed ? 99999 : (days <= 2 ? 500 : days <= 4 ? 1000 : 99999);

  const scored = DESTINATIONS
    .filter(d => d.purpose_tags.includes(purpose))
    .filter(d => {
      if (!depCoords) return true;
      return haversineKm(depCoords.lat, depCoords.lng, d.lat, d.lng) <= maxDistanceKm;
    })
    .map(d => {
      let score = 0;
      if (d.purpose_tags[0] === purpose) score += 40;
      if (d.avg_daily_cost <= maxCost) score += 30;
      if (d.crowd_level === 'Low') score += 20;
      else if (d.crowd_level === 'Medium') score += 10;

      // Proximity bonus: destinations closer to the departure city rank higher
      if (depCoords) {
        const dist = haversineKm(depCoords.lat, depCoords.lng, d.lat, d.lng);
        if (dist < 200)      score += 15;
        else if (dist < 400) score += 10;
        else if (dist < 600) score += 5;
      }

      score += Math.floor(Math.random() * 10); // slight randomisation
      return { ...d, match_pct: Math.min(99, score), estimated_total: d.avg_daily_cost * days };
    })
    .sort((a, b) => b.match_pct - a.match_pct)
    .slice(0, 3);

  // Fallback: if the distance filter was too strict (very few nearby destinations
  // for this purpose/budget combo), retry without the proximity filter.
  if (scored.length < 3 && depCoords && !_relaxed) {
    return matchDestinations(purpose, budget, days, departure, true);
  }

  return scored;
}